from flask import Flask, session
from flask_redis import FlaskRedis
from functools import wraps

app = Flask(__name__)
app.config['REDIS_URL'] = 'redis://localhost:6379'
redis_store = FlaskRedis(app)

@app.route('/')
def index():
    session['username'] = 'John Doe'
    return f'Hello, {session.get("username")}'

@app.route('/cache')
@redis_cache()
def expensive_query():
    return str(sum(i**2 for i in range(10000)))

def redis_cache(timeout=3600):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            key = func.__name__
            result = redis_store.get(key)
            if result is None:
                result = func(*args, **kwargs)
                redis_store.set(key, result, timeout)
            return result
        return wrapper
    return decorator

